#include <iostream>
using namespace std;

// Three 'print' functions:
void print(int n) {
    cout << "int: " << n << endl;
}
void print(double d) {
    cout << "double: " << d << endl;
}
void print(string s) {
    cout << "string: " << s << endl;
}

int main() {
    print(42);       // int: 42
    print(3.14);     // double: 3.14
    print("hello");  // string: hello
}

void connect(string host, int port=80, bool ssl=false) {
    cout << host << ":" << port;
    if (ssl) cout << " (SSL)";
    cout << endl;
}

connect("example.com");         // example.com:80
connect("example.com", 443);    // example.com:443
connect("example.com", 443, true); // example.com:443 (SSL)

