#include <iostream>
using namespace std;

// C++ pass by reference — clean!
void doubleRef(int& x) {
    x *= 2;  // NO * needed!
}

// C-style pointer version (also works in C++):
void doublePtr(int* x) {
    *x *= 2;  // needs dereference
}

int n = 5;
doubleRef(n);   // n is now 10
doublePtr(&n);  // n is now 20
cout << n;      // 20

// Efficient: avoids copying large strings
void printInfo(const string& name) {
    cout << name << endl;
    // name = 'X'; // ERROR — const!
}

// Swap using references (no pointers!):
void swap(int& a, int& b) {
    int temp = a;
    a = b;
    b = temp;
}

int x=5, y=10;
swap(x, y);
cout << x << " " << y; // 10 5

