#include <algorithm>
#include <vector>
using namespace std;

// Basic lambda:
auto greet = [](string name) {
    cout << "Hello, " << name << endl;
};
greet("Neo");  // Hello, Neo

// Lambda with STL:
vector<int> v = {5,2,8,1,9,3};
sort(v.begin(), v.end(), [](int a, int b){
    return a < b;  // ascending sort
});
// v = {1,2,3,5,8,9}

int threshold = 5;
vector<int> v = {3,7,1,9,4};

// [threshold] captures by value:
for_each(v.begin(), v.end(),
    [threshold](int x) {
        if(x > threshold) cout << x << " ";
    });
// 7 9

// [&threshold] captures by reference:
// [=] captures all by value
// [&] captures all by reference

// inline — compiler may inline this:
inline int max(int a, int b) {
    return a > b ? a : b;
}

// Effectively becomes:
int x = max(5, 3);
// Compiler may transform to:
// int x = (5 > 3) ? 5 : 3;  // no call overhead!

// Common in .h files (avoid ODR violations):
// Each translation unit gets its own copy
inline void log(const string& s) {
    cout << "[LOG] " << s << endl;
}

